use std::arch::x86_64::*;

/// Compute squared L2 distance between two 128-dimensional f32 vectors.
/// Returns as f64 for precision.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);
    l2_distance_avx512(a, b) as f64
}

/// AVX-512 optimized L2 squared distance for 128-dim vectors.
/// 128 floats * 4 bytes = 512 bytes = 32 AVX-512 floats per register, so 8 registers.
#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    unsafe {
        if is_x86_feature_detected!("avx512f") {
            return l2_distance_avx512_inner(a, b);
        }
        if is_x86_feature_detected!("avx2") {
            return l2_distance_avx2_inner(a, b);
        }
        l2_distance_scalar(a, b)
    }
}

#[cfg(not(target_arch = "x86_64"))]
#[inline(always)]
fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512_inner(a: &[f32], b: &[f32]) -> f32 {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();
    let mut sum2 = _mm512_setzero_ps();
    let mut sum3 = _mm512_setzero_ps();

    // 128 floats / 16 per register = 8 iterations, unroll by 4 = 2 outer iterations
    // Actually let's do 8 iterations with 4-way unroll covering all 128
    let mut i = 0usize;
    while i < 128 {
        let va0 = _mm512_loadu_ps(a_ptr.add(i));
        let vb0 = _mm512_loadu_ps(b_ptr.add(i));
        let d0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(d0, d0, sum0);

        let va1 = _mm512_loadu_ps(a_ptr.add(i + 16));
        let vb1 = _mm512_loadu_ps(b_ptr.add(i + 16));
        let d1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(d1, d1, sum1);

        let va2 = _mm512_loadu_ps(a_ptr.add(i + 32));
        let vb2 = _mm512_loadu_ps(b_ptr.add(i + 32));
        let d2 = _mm512_sub_ps(va2, vb2);
        sum2 = _mm512_fmadd_ps(d2, d2, sum2);

        let va3 = _mm512_loadu_ps(a_ptr.add(i + 48));
        let vb3 = _mm512_loadu_ps(b_ptr.add(i + 48));
        let d3 = _mm512_sub_ps(va3, vb3);
        sum3 = _mm512_fmadd_ps(d3, d3, sum3);

        i += 64;
    }

    let sum = _mm512_add_ps(_mm512_add_ps(sum0, sum1), _mm512_add_ps(sum2, sum3));
    _mm512_reduce_add_ps(sum)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2", enable = "fma")]
#[inline]
unsafe fn l2_distance_avx2_inner(a: &[f32], b: &[f32]) -> f32 {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    let mut sum0 = _mm256_setzero_ps();
    let mut sum1 = _mm256_setzero_ps();
    let mut sum2 = _mm256_setzero_ps();
    let mut sum3 = _mm256_setzero_ps();

    let mut i = 0usize;
    while i < 128 {
        let va0 = _mm256_loadu_ps(a_ptr.add(i));
        let vb0 = _mm256_loadu_ps(b_ptr.add(i));
        let d0 = _mm256_sub_ps(va0, vb0);
        sum0 = _mm256_fmadd_ps(d0, d0, sum0);

        let va1 = _mm256_loadu_ps(a_ptr.add(i + 8));
        let vb1 = _mm256_loadu_ps(b_ptr.add(i + 8));
        let d1 = _mm256_sub_ps(va1, vb1);
        sum1 = _mm256_fmadd_ps(d1, d1, sum1);

        let va2 = _mm256_loadu_ps(a_ptr.add(i + 16));
        let vb2 = _mm256_loadu_ps(b_ptr.add(i + 16));
        let d2 = _mm256_sub_ps(va2, vb2);
        sum2 = _mm256_fmadd_ps(d2, d2, sum2);

        let va3 = _mm256_loadu_ps(a_ptr.add(i + 24));
        let vb3 = _mm256_loadu_ps(b_ptr.add(i + 24));
        let d3 = _mm256_sub_ps(va3, vb3);
        sum3 = _mm256_fmadd_ps(d3, d3, sum3);

        i += 32;
    }

    let sum = _mm256_add_ps(_mm256_add_ps(sum0, sum1), _mm256_add_ps(sum2, sum3));
    // horizontal sum
    let hi = _mm256_extractf128_ps(sum, 1);
    let lo = _mm256_castps256_ps128(sum);
    let sum128 = _mm_add_ps(lo, hi);
    let sum64 = _mm_add_ps(sum128, _mm_movehl_ps(sum128, sum128));
    let sum32 = _mm_add_ss(sum64, _mm_shuffle_ps(sum64, sum64, 1));
    _mm_cvtss_f32(sum32)
}

#[inline]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    let mut sum = 0.0f32;
    for i in 0..a.len() {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}

/// Batch compute L2 distances from a query to multiple vectors stored contiguously.
/// Returns distances as f32.
#[inline]
pub fn l2_distance_batch(query: &[f32], data: &[f32], dim: usize, count: usize, results: &mut [f32]) {
    debug_assert_eq!(query.len(), dim);
    debug_assert!(data.len() >= count * dim);
    debug_assert!(results.len() >= count);

    for i in 0..count {
        let offset = i * dim;
        let vec_slice = &data[offset..offset + dim];
        results[i] = unsafe { l2_distance_fast(query, vec_slice) };
    }
}

#[inline(always)]
pub unsafe fn l2_distance_fast(a: &[f32], b: &[f32]) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") {
            return l2_distance_avx512_inner(a, b);
        }
        if is_x86_feature_detected!("avx2") {
            return l2_distance_avx2_inner(a, b);
        }
    }
    l2_distance_scalar(a, b)
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 256;
const NPROBE: usize = 16;
const KMEANS_ITERS: usize = 10;
const KMEANS_SAMPLE_SIZE: usize = 50000;

/// A cluster in the IVF index
struct Cluster {
    centroid: Vec<f32>,
    /// Flat storage: ids and vectors stored contiguously
    ids: Vec<u64>,
    vectors: Vec<f32>, // ids.len() * DIM floats
}

pub struct VectorDB {
    /// Raw storage for all vectors (append-only)
    all_ids: RwLock<Vec<u64>>,
    all_vectors: RwLock<Vec<f32>>, // flat: n * DIM

    /// IVF index
    clusters: RwLock<Vec<Cluster>>,
    index_built: AtomicBool,
    vector_count: AtomicUsize,
}

impl VectorDB {
    pub fn new() -> Self {
        // Initialize rayon thread pool with 4 threads
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            all_ids: RwLock::new(Vec::new()),
            all_vectors: RwLock::new(Vec::new()),
            clusters: RwLock::new(Vec::new()),
            index_built: AtomicBool::new(false),
            vector_count: AtomicUsize::new(0),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        debug_assert_eq!(vector.len(), DIM);

        if self.index_built.load(Ordering::Relaxed) {
            // Add to the appropriate cluster
            let clusters = self.clusters.read();
            let best_cluster = self.find_nearest_cluster(&vector, &clusters);
            drop(clusters);

            let mut clusters = self.clusters.write();
            clusters[best_cluster].ids.push(id);
            clusters[best_cluster].vectors.extend_from_slice(&vector);
        } else {
            let mut ids = self.all_ids.write();
            let mut vecs = self.all_vectors.write();
            ids.push(id);
            vecs.extend_from_slice(&vector);
        }
        self.vector_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        if self.index_built.load(Ordering::Relaxed) {
            // Assign each vector to nearest cluster
            let clusters_r = self.clusters.read();
            let centroids: Vec<&[f32]> = clusters_r.iter().map(|c| c.centroid.as_slice()).collect();
            drop(clusters_r);

            // Compute assignments
            let assignments: Vec<(usize, u64, Vec<f32>)> = vectors
                .into_iter()
                .map(|(id, vec)| {
                    let best = self.find_nearest_centroid(&vec, &centroids);
                    (best, id, vec)
                })
                .collect();

            let mut clusters = self.clusters.write();
            for (cluster_idx, id, vec) in assignments {
                clusters[cluster_idx].ids.push(id);
                clusters[cluster_idx].vectors.extend_from_slice(&vec);
            }
        } else {
            let mut ids = self.all_ids.write();
            let mut vecs = self.all_vectors.write();
            ids.reserve(count);
            vecs.reserve(count * DIM);
            for (id, vector) in &vectors {
                ids.push(*id);
                vecs.extend_from_slice(vector);
            }

            drop(ids);
            drop(vecs);

            let total = self.vector_count.load(Ordering::Relaxed) + count;
            self.vector_count.store(total, Ordering::Relaxed);

            // Build index when we have enough vectors
            if total >= 900_000 {
                self.build_index();
            } else {
                // Don't add to count yet if we haven't reached threshold and returned early
                return count;
            }
            return count;
        }

        self.vector_count.fetch_add(count, Ordering::Relaxed);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        if self.index_built.load(Ordering::Acquire) {
            return self.search_ivf(vector, top_k);
        }

        // Brute force fallback
        self.search_brute_force(vector, top_k)
    }

    fn build_index(&self) {
        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        eprintln!("Building IVF index with {} vectors, {} clusters...", n, NUM_CLUSTERS);

        // K-means clustering
        let centroids = self.kmeans(&vectors, n);

        // Assign vectors to clusters
        let mut cluster_data: Vec<(Vec<u64>, Vec<f32>)> = (0..NUM_CLUSTERS)
            .map(|_| (Vec::new(), Vec::new()))
            .collect();

        // Parallel assignment
        let centroid_refs: Vec<&[f32]> = centroids.chunks(DIM).collect();

        // Process in chunks for parallelism
        let chunk_size = 10000;
        let chunk_results: Vec<Vec<usize>> = (0..n)
            .into_par_iter()
            .map(|i| {
                let vec = &vectors[i * DIM..(i + 1) * DIM];
                self.find_nearest_centroid(vec, &centroid_refs)
            })
            .collect();

        for i in 0..n {
            let cluster_idx = chunk_results[i];
            cluster_data[cluster_idx].0.push(ids[i]);
            cluster_data[cluster_idx].1.extend_from_slice(&vectors[i * DIM..(i + 1) * DIM]);
        }

        let clusters: Vec<Cluster> = (0..NUM_CLUSTERS)
            .map(|c| {
                let (cids, cvecs) = std::mem::take(&mut cluster_data[c]);
                Cluster {
                    centroid: centroids[c * DIM..(c + 1) * DIM].to_vec(),
                    ids: cids,
                    vectors: cvecs,
                }
            })
            .collect();

        eprintln!("IVF index built. Cluster sizes: min={}, max={}, avg={}",
            clusters.iter().map(|c| c.ids.len()).min().unwrap_or(0),
            clusters.iter().map(|c| c.ids.len()).max().unwrap_or(0),
            n / NUM_CLUSTERS,
        );

        *self.clusters.write() = clusters;
        self.index_built.store(true, Ordering::Release);
    }

    fn kmeans(&self, vectors: &[f32], n: usize) -> Vec<f32> {
        // Subsample for speed
        let sample_size = KMEANS_SAMPLE_SIZE.min(n);
        let step = n / sample_size;

        let sample_indices: Vec<usize> = (0..sample_size).map(|i| i * step).collect();

        // Initialize centroids with k-means++ style: evenly spaced
        let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
        let init_step = sample_size / NUM_CLUSTERS;
        for c in 0..NUM_CLUSTERS {
            let idx = sample_indices[c * init_step];
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&vectors[idx * DIM..(idx + 1) * DIM]);
        }

        let centroid_refs_fn = |cents: &Vec<f32>| -> Vec<Vec<f32>> {
            cents.chunks(DIM).map(|c| c.to_vec()).collect()
        };

        // K-means iterations
        for iter in 0..KMEANS_ITERS {
            let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

            // Assign samples to clusters in parallel
            let assignments: Vec<usize> = sample_indices
                .par_iter()
                .map(|&idx| {
                    let vec = &vectors[idx * DIM..(idx + 1) * DIM];
                    self.find_nearest_centroid(vec, &centroid_slices)
                })
                .collect();

            // Compute new centroids
            let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
            let mut counts = vec![0usize; NUM_CLUSTERS];

            for (si, &cluster_idx) in assignments.iter().enumerate() {
                let idx = sample_indices[si];
                counts[cluster_idx] += 1;
                for d in 0..DIM {
                    new_centroids[cluster_idx * DIM + d] += vectors[idx * DIM + d] as f64;
                }
            }

            for c in 0..NUM_CLUSTERS {
                if counts[c] > 0 {
                    for d in 0..DIM {
                        centroids[c * DIM + d] = (new_centroids[c * DIM + d] / counts[c] as f64) as f32;
                    }
                }
                // Keep old centroid if no assignments
            }
        }

        centroids
    }

    #[inline]
    fn find_nearest_centroid(&self, vec: &[f32], centroids: &[&[f32]]) -> usize {
        let mut best_idx = 0;
        let mut best_dist = f32::MAX;
        for (i, centroid) in centroids.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(vec, centroid) };
            if dist < best_dist {
                best_dist = dist;
                best_idx = i;
            }
        }
        best_idx
    }

    #[inline]
    fn find_nearest_cluster(&self, vec: &[f32], clusters: &[Cluster]) -> usize {
        let mut best_idx = 0;
        let mut best_dist = f32::MAX;
        for (i, cluster) in clusters.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(vec, &cluster.centroid) };
            if dist < best_dist {
                best_dist = dist;
                best_idx = i;
            }
        }
        best_idx
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let clusters = self.clusters.read();

        // Find NPROBE nearest clusters
        let mut cluster_dists: Vec<(usize, f32)> = clusters
            .iter()
            .enumerate()
            .map(|(i, c)| {
                let dist = unsafe { distance::l2_distance_fast(query, &c.centroid) };
                (i, dist)
            })
            .collect();

        cluster_dists.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

        let probe_clusters: Vec<usize> = cluster_dists.iter().take(NPROBE).map(|&(i, _)| i).collect();

        // Search within the selected clusters in parallel
        let results: Vec<Vec<(u64, f32)>> = probe_clusters
            .par_iter()
            .map(|&cluster_idx| {
                let cluster = &clusters[cluster_idx];
                let n = cluster.ids.len();
                if n == 0 {
                    return Vec::new();
                }

                // Use a max-heap (BinaryHeap) approach with partial sort
                let mut top: Vec<(u64, f32)> = Vec::with_capacity(top_k + 1);

                for i in 0..n {
                    let vec_slice = &cluster.vectors[i * DIM..(i + 1) * DIM];
                    let dist = unsafe { distance::l2_distance_fast(query, vec_slice) };

                    if top.len() < top_k {
                        top.push((cluster.ids[i], dist));
                        if top.len() == top_k {
                            // Sort descending by distance so we can check top[0] as max
                            top.sort_unstable_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
                        }
                    } else if dist < top[0].1 {
                        top[0] = (cluster.ids[i], dist);
                        // Re-sort to maintain max at front
                        top.sort_unstable_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
                    }
                }

                top
            })
            .collect();

        // Merge results
        let mut all_results: Vec<(u64, f32)> = results.into_iter().flatten().collect();
        all_results.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        all_results.truncate(top_k);

        all_results
            .into_iter()
            .map(|(id, dist)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return Vec::new();
        }

        // Parallel brute force
        let chunk_size = (n + 3) / 4;
        let results: Vec<Vec<(u64, f32)>> = (0..4)
            .into_par_iter()
            .map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                let mut top: Vec<(u64, f32)> = Vec::with_capacity(top_k + 1);

                for i in start..end {
                    let vec_slice = &vectors[i * DIM..(i + 1) * DIM];
                    let dist = unsafe { distance::l2_distance_fast(query, vec_slice) };

                    if top.len() < top_k {
                        top.push((ids[i], dist));
                        if top.len() == top_k {
                            top.sort_unstable_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
                        }
                    } else if dist < top[0].1 {
                        top[0] = (ids[i], dist);
                        top.sort_unstable_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
                    }
                }

                top
            })
            .collect();

        let mut all_results: Vec<(u64, f32)> = results.into_iter().flatten().collect();
        all_results.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        all_results.truncate(top_k);

        all_results
            .into_iter()
            .map(|(id, dist)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }
}
"}

