use std::arch::x86_64::*;

/// Compute squared L2 distance between two 128-dimensional f32 vectors.
/// Returns as f64 for precision.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    unsafe { l2_distance_fast(a, b) as f64 }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
pub unsafe fn l2_distance_avx512_inner(a: &[f32], b: &[f32]) -> f32 {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();
    let mut sum2 = _mm512_setzero_ps();
    let mut sum3 = _mm512_setzero_ps();

    let mut i = 0usize;
    while i < 128 {
        let va0 = _mm512_loadu_ps(a_ptr.add(i));
        let vb0 = _mm512_loadu_ps(b_ptr.add(i));
        let d0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(d0, d0, sum0);

        let va1 = _mm512_loadu_ps(a_ptr.add(i + 16));
        let vb1 = _mm512_loadu_ps(b_ptr.add(i + 16));
        let d1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(d1, d1, sum1);

        let va2 = _mm512_loadu_ps(a_ptr.add(i + 32));
        let vb2 = _mm512_loadu_ps(b_ptr.add(i + 32));
        let d2 = _mm512_sub_ps(va2, vb2);
        sum2 = _mm512_fmadd_ps(d2, d2, sum2);

        let va3 = _mm512_loadu_ps(a_ptr.add(i + 48));
        let vb3 = _mm512_loadu_ps(b_ptr.add(i + 48));
        let d3 = _mm512_sub_ps(va3, vb3);
        sum3 = _mm512_fmadd_ps(d3, d3, sum3);

        i += 64;
    }

    let sum = _mm512_add_ps(_mm512_add_ps(sum0, sum1), _mm512_add_ps(sum2, sum3));
    _mm512_reduce_add_ps(sum)
}

/// Fast L2 distance - always uses AVX-512 since we know this CPU has it.
/// Feature detection is done once.
#[inline(always)]
pub unsafe fn l2_distance_fast(a: &[f32], b: &[f32]) -> f32 {
    l2_distance_avx512_inner(a, b)
}

/// Compute L2 distances from query to a contiguous block of vectors, storing results
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
pub unsafe fn l2_distances_batch(
    query: &[f32],
    vectors: &[f32],  // contiguous block of n*128 floats
    n: usize,
    results: &mut [f32],
) {
    let q_ptr = query.as_ptr();
    let v_ptr = vectors.as_ptr();

    for i in 0..n {
        let b_ptr = v_ptr.add(i * 128);
        let mut sum0 = _mm512_setzero_ps();
        let mut sum1 = _mm512_setzero_ps();
        let mut sum2 = _mm512_setzero_ps();
        let mut sum3 = _mm512_setzero_ps();

        let mut j = 0usize;
        while j < 128 {
            let va0 = _mm512_loadu_ps(q_ptr.add(j));
            let vb0 = _mm512_loadu_ps(b_ptr.add(j));
            let d0 = _mm512_sub_ps(va0, vb0);
            sum0 = _mm512_fmadd_ps(d0, d0, sum0);

            let va1 = _mm512_loadu_ps(q_ptr.add(j + 16));
            let vb1 = _mm512_loadu_ps(b_ptr.add(j + 16));
            let d1 = _mm512_sub_ps(va1, vb1);
            sum1 = _mm512_fmadd_ps(d1, d1, sum1);

            let va2 = _mm512_loadu_ps(q_ptr.add(j + 32));
            let vb2 = _mm512_loadu_ps(b_ptr.add(j + 32));
            let d2 = _mm512_sub_ps(va2, vb2);
            sum2 = _mm512_fmadd_ps(d2, d2, sum2);

            let va3 = _mm512_loadu_ps(q_ptr.add(j + 48));
            let vb3 = _mm512_loadu_ps(b_ptr.add(j + 48));
            let d3 = _mm512_sub_ps(va3, vb3);
            sum3 = _mm512_fmadd_ps(d3, d3, sum3);

            j += 64;
        }

        let sum = _mm512_add_ps(_mm512_add_ps(sum0, sum1), _mm512_add_ps(sum2, sum3));
        *results.get_unchecked_mut(i) = _mm512_reduce_add_ps(sum);
    }
}
