use crate::distance;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 512;
const NPROBE: usize = 24;
const KMEANS_ITERS: usize = 10;
const KMEANS_SAMPLE_SIZE: usize = 50000;

/// A cluster in the IVF index
struct Cluster {
    centroid: [f32; DIM],
    /// Flat storage: ids and vectors stored contiguously
    ids: Vec<u64>,
    vectors: Vec<f32>, // ids.len() * DIM floats
}

pub struct VectorDB {
    /// Raw storage for all vectors (append-only, pre-index)
    all_ids: RwLock<Vec<u64>>,
    all_vectors: RwLock<Vec<f32>>, // flat: n * DIM

    /// IVF index
    clusters: RwLock<Vec<Cluster>>,
    index_built: AtomicBool,
    vector_count: AtomicUsize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            all_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            all_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            clusters: RwLock::new(Vec::new()),
            index_built: AtomicBool::new(false),
            vector_count: AtomicUsize::new(0),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if self.index_built.load(Ordering::Relaxed) {
            let clusters = self.clusters.read();
            let best_cluster = self.find_nearest_cluster_idx(&vector, &clusters);
            drop(clusters);

            let mut clusters = self.clusters.write();
            clusters[best_cluster].ids.push(id);
            clusters[best_cluster].vectors.extend_from_slice(&vector);
        } else {
            let mut ids = self.all_ids.write();
            let mut vecs = self.all_vectors.write();
            ids.push(id);
            vecs.extend_from_slice(&vector);
        }
        self.vector_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        if self.index_built.load(Ordering::Relaxed) {
            let clusters_r = self.clusters.read();
            let centroids: Vec<[f32; DIM]> = clusters_r.iter().map(|c| c.centroid).collect();
            drop(clusters_r);

            let centroid_refs: Vec<&[f32]> = centroids.iter().map(|c| c.as_slice()).collect();

            let assignments: Vec<(usize, u64, Vec<f32>)> = vectors
                .into_iter()
                .map(|(id, vec)| {
                    let best = find_nearest_centroid_static(&vec, &centroid_refs);
                    (best, id, vec)
                })
                .collect();

            let mut clusters = self.clusters.write();
            for (cluster_idx, id, vec) in assignments {
                clusters[cluster_idx].ids.push(id);
                clusters[cluster_idx].vectors.extend_from_slice(&vec);
            }
            self.vector_count.fetch_add(count, Ordering::Relaxed);
        } else {
            {
                let mut ids = self.all_ids.write();
                let mut vecs = self.all_vectors.write();
                ids.reserve(count);
                vecs.reserve(count * DIM);
                for (id, vector) in &vectors {
                    ids.push(*id);
                    vecs.extend_from_slice(vector);
                }
            }

            let total = self.vector_count.fetch_add(count, Ordering::Relaxed) + count;

            if total >= 900_000 {
                self.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        if self.index_built.load(Ordering::Acquire) {
            return self.search_ivf(vector, top_k);
        }

        self.search_brute_force(vector, top_k)
    }

    fn build_index(&self) {
        // Prevent multiple builds
        if self.index_built.load(Ordering::Relaxed) {
            return;
        }

        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return;
        }

        eprintln!("Building IVF index with {} vectors, {} clusters...", n, NUM_CLUSTERS);

        let centroids = self.kmeans(&vectors, n);

        let mut cluster_data: Vec<(Vec<u64>, Vec<f32>)> = (0..NUM_CLUSTERS)
            .map(|_| (Vec::with_capacity(n / NUM_CLUSTERS * 2), Vec::with_capacity(n / NUM_CLUSTERS * 2 * DIM)))
            .collect();

        let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

        let assignments: Vec<usize> = (0..n)
            .into_par_iter()
            .map(|i| {
                let vec = &vectors[i * DIM..(i + 1) * DIM];
                find_nearest_centroid_static(vec, &centroid_slices)
            })
            .collect();

        for i in 0..n {
            let ci = assignments[i];
            cluster_data[ci].0.push(ids[i]);
            cluster_data[ci].1.extend_from_slice(&vectors[i * DIM..(i + 1) * DIM]);
        }

        let clusters: Vec<Cluster> = (0..NUM_CLUSTERS)
            .map(|c| {
                let (cids, cvecs) = std::mem::take(&mut cluster_data[c]);
                let mut centroid = [0.0f32; DIM];
                centroid.copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                Cluster {
                    centroid,
                    ids: cids,
                    vectors: cvecs,
                }
            })
            .collect();

        eprintln!("IVF index built. Cluster sizes: min={}, max={}, avg={}",
            clusters.iter().map(|c| c.ids.len()).min().unwrap_or(0),
            clusters.iter().map(|c| c.ids.len()).max().unwrap_or(0),
            n / NUM_CLUSTERS,
        );

        *self.clusters.write() = clusters;
        self.index_built.store(true, Ordering::Release);
    }

    fn kmeans(&self, vectors: &[f32], n: usize) -> Vec<f32> {
        let sample_size = KMEANS_SAMPLE_SIZE.min(n);
        let step = if n > sample_size { n / sample_size } else { 1 };

        let sample_indices: Vec<usize> = (0..sample_size).map(|i| (i * step).min(n - 1)).collect();

        let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
        let init_step = if sample_size > NUM_CLUSTERS { sample_size / NUM_CLUSTERS } else { 1 };
        for c in 0..NUM_CLUSTERS {
            let idx = sample_indices[(c * init_step).min(sample_size - 1)];
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&vectors[idx * DIM..(idx + 1) * DIM]);
        }

        for _iter in 0..KMEANS_ITERS {
            let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

            let assignments: Vec<usize> = sample_indices
                .par_iter()
                .map(|&idx| {
                    let vec = &vectors[idx * DIM..(idx + 1) * DIM];
                    find_nearest_centroid_static(vec, &centroid_slices)
                })
                .collect();

            let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
            let mut counts = vec![0usize; NUM_CLUSTERS];

            for (si, &cluster_idx) in assignments.iter().enumerate() {
                let idx = sample_indices[si];
                counts[cluster_idx] += 1;
                let base = cluster_idx * DIM;
                let vbase = idx * DIM;
                for d in 0..DIM {
                    new_centroids[base + d] += vectors[vbase + d] as f64;
                }
            }

            for c in 0..NUM_CLUSTERS {
                if counts[c] > 0 {
                    let inv = 1.0 / counts[c] as f64;
                    for d in 0..DIM {
                        centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                    }
                }
            }
        }

        centroids
    }

    #[inline]
    fn find_nearest_cluster_idx(&self, vec: &[f32], clusters: &[Cluster]) -> usize {
        let mut best_idx = 0;
        let mut best_dist = f32::MAX;
        for (i, cluster) in clusters.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(vec, &cluster.centroid) };
            if dist < best_dist {
                best_dist = dist;
                best_idx = i;
            }
        }
        best_idx
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let clusters = self.clusters.read();

        // Find NPROBE nearest clusters
        let mut cluster_dists: Vec<(usize, f32)> = Vec::with_capacity(NUM_CLUSTERS);
        for (i, c) in clusters.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(query, &c.centroid) };
            cluster_dists.push((i, dist));
        }

        // Partial sort to find top NPROBE
        cluster_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        let probe_clusters = &cluster_dists[..NPROBE];

        // Search within selected clusters
        let mut top_k_heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut max_dist = f32::MAX;

        for &(cluster_idx, _) in probe_clusters {
            let cluster = &clusters[cluster_idx];
            let n = cluster.ids.len();
            if n == 0 {
                continue;
            }

            // Batch compute distances
            let mut dists = vec![0.0f32; n];
            unsafe {
                distance::l2_distances_batch(query, &cluster.vectors, n, &mut dists);
            }

            for i in 0..n {
                let dist = dists[i];
                if top_k_heap.len() < top_k {
                    top_k_heap.push((dist, cluster.ids[i]));
                    if top_k_heap.len() == top_k {
                        // Build max-heap: sort descending so max is at [0]
                        top_k_heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        max_dist = top_k_heap[0].0;
                    }
                } else if dist < max_dist {
                    top_k_heap[0] = (dist, cluster.ids[i]);
                    // Re-heapify: find new max
                    // For small top_k (10), a simple sort is fast
                    top_k_heap.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                    max_dist = top_k_heap[0].0;
                }
            }
        }

        top_k_heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        top_k_heap.truncate(top_k);

        top_k_heap
            .into_iter()
            .map(|(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return Vec::new();
        }

        let chunk_size = (n + 3) / 4;
        let results: Vec<Vec<(f32, u64)>> = (0..4)
            .into_par_iter()
            .map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                let mut top: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
                let mut max_dist = f32::MAX;

                for i in start..end {
                    let vec_slice = &vectors[i * DIM..(i + 1) * DIM];
                    let dist = unsafe { distance::l2_distance_fast(query, vec_slice) };

                    if top.len() < top_k {
                        top.push((dist, ids[i]));
                        if top.len() == top_k {
                            top.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                            max_dist = top[0].0;
                        }
                    } else if dist < max_dist {
                        top[0] = (dist, ids[i]);
                        top.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap());
                        max_dist = top[0].0;
                    }
                }

                top
            })
            .collect();

        let mut all_results: Vec<(f32, u64)> = results.into_iter().flatten().collect();
        all_results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        all_results.truncate(top_k);

        all_results
            .into_iter()
            .map(|(dist, id)| SearchResult {
                id,
                distance: dist as f64,
            })
            .collect()
    }
}

#[inline]
fn find_nearest_centroid_static(vec: &[f32], centroids: &[&[f32]]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::MAX;
    for (i, centroid) in centroids.iter().enumerate() {
        let dist = unsafe { distance::l2_distance_fast(vec, centroid) };
        if dist < best_dist {
            best_dist = dist;
            best_idx = i;
        }
    }
    best_idx
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use std::collections::BinaryHeap;
use std::cmp::Ordering as CmpOrdering;

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 32;
const KMEANS_ITERS: usize = 12;
const KMEANS_SAMPLE_SIZE: usize = 80000;

/// Wrapper for f32 distance in a max-heap (reverse ordering for min-k)
#[derive(Clone, Copy)]
struct DistId {
    dist: f32,
    id: u64,
}

impl PartialEq for DistId {
    fn eq(&self, other: &Self) -> bool {
        self.dist == other.dist
    }
}
impl Eq for DistId {}

impl PartialOrd for DistId {
    fn partial_cmp(&self, other: &Self) -> Option<CmpOrdering> {
        // Max-heap by distance
        self.dist.partial_cmp(&other.dist)
    }
}

impl Ord for DistId {
    fn cmp(&self, other: &Self) -> CmpOrdering {
        self.dist.partial_cmp(&other.dist).unwrap_or(CmpOrdering::Equal)
    }
}

/// A cluster in the IVF index
struct Cluster {
    centroid: [f32; DIM],
    ids: Vec<u64>,
    vectors: Vec<f32>, // ids.len() * DIM floats, contiguous
}

/// Read-only snapshot of clusters for lock-free searching
struct IndexSnapshot {
    clusters: Vec<Cluster>,
}

unsafe impl Send for IndexSnapshot {}
unsafe impl Sync for IndexSnapshot {}

pub struct VectorDB {
    /// Raw storage for all vectors (append-only, pre-index)
    all_ids: RwLock<Vec<u64>>,
    all_vectors: RwLock<Vec<f32>>,

    /// IVF index - once built, treated as read-only
    snapshot: RwLock<Option<Box<IndexSnapshot>>>,
    index_built: AtomicBool,
    vector_count: AtomicUsize,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            all_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            all_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIM)),
            snapshot: RwLock::new(None),
            index_built: AtomicBool::new(false),
            vector_count: AtomicUsize::new(0),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if self.index_built.load(Ordering::Relaxed) {
            // After index is built, add to appropriate cluster
            let mut snap = self.snapshot.write();
            if let Some(ref mut s) = *snap {
                let best = find_nearest_cluster_in_snapshot(&vector, &s.clusters);
                s.clusters[best].ids.push(id);
                s.clusters[best].vectors.extend_from_slice(&vector);
            }
        } else {
            let mut ids = self.all_ids.write();
            let mut vecs = self.all_vectors.write();
            ids.push(id);
            vecs.extend_from_slice(&vector);
        }
        self.vector_count.fetch_add(1, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        if self.index_built.load(Ordering::Relaxed) {
            // After index built
            let snap_r = self.snapshot.read();
            if let Some(ref s) = *snap_r {
                let centroid_data: Vec<&[f32]> = s.clusters.iter().map(|c| c.centroid.as_slice()).collect();
                drop(snap_r);

                let assignments: Vec<(usize, u64, Vec<f32>)> = vectors
                    .into_iter()
                    .map(|(id, vec)| {
                        let best = find_nearest_centroid_static(&vec, &centroid_data);
                        (best, id, vec)
                    })
                    .collect();

                let mut snap = self.snapshot.write();
                if let Some(ref mut s) = *snap {
                    for (ci, id, vec) in assignments {
                        s.clusters[ci].ids.push(id);
                        s.clusters[ci].vectors.extend_from_slice(&vec);
                    }
                }
            }
            self.vector_count.fetch_add(count, Ordering::Relaxed);
        } else {
            {
                let mut ids = self.all_ids.write();
                let mut vecs = self.all_vectors.write();
                for (id, vector) in &vectors {
                    ids.push(*id);
                    vecs.extend_from_slice(vector);
                }
            }

            let total = self.vector_count.fetch_add(count, Ordering::Relaxed) + count;
            if total >= 900_000 && !self.index_built.load(Ordering::Relaxed) {
                self.build_index();
            }
        }

        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        if self.index_built.load(Ordering::Acquire) {
            return self.search_ivf(vector, top_k);
        }

        self.search_brute_force(vector, top_k)
    }

    fn build_index(&self) {
        if self.index_built.swap(true, Ordering::SeqCst) {
            return; // Another thread already building
        }

        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            self.index_built.store(false, Ordering::SeqCst);
            return;
        }

        eprintln!("Building IVF index with {} vectors, {} clusters...", n, NUM_CLUSTERS);

        let centroids = kmeans(&vectors, n);

        let mut cluster_ids: Vec<Vec<u64>> = (0..NUM_CLUSTERS).map(|_| Vec::with_capacity(n / NUM_CLUSTERS + 100)).collect();
        let mut cluster_vecs: Vec<Vec<f32>> = (0..NUM_CLUSTERS).map(|_| Vec::with_capacity((n / NUM_CLUSTERS + 100) * DIM)).collect();

        let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

        let assignments: Vec<usize> = (0..n)
            .into_par_iter()
            .map(|i| {
                let vec = &vectors[i * DIM..(i + 1) * DIM];
                find_nearest_centroid_static(vec, &centroid_slices)
            })
            .collect();

        for i in 0..n {
            let ci = assignments[i];
            cluster_ids[ci].push(ids[i]);
            cluster_vecs[ci].extend_from_slice(&vectors[i * DIM..(i + 1) * DIM]);
        }

        let clusters: Vec<Cluster> = (0..NUM_CLUSTERS)
            .map(|c| {
                let cids = std::mem::take(&mut cluster_ids[c]);
                let cvecs = std::mem::take(&mut cluster_vecs[c]);
                let mut centroid = [0.0f32; DIM];
                centroid.copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                Cluster {
                    centroid,
                    ids: cids,
                    vectors: cvecs,
                }
            })
            .collect();

        eprintln!("IVF index built. Cluster sizes: min={}, max={}, avg={}",
            clusters.iter().map(|c| c.ids.len()).min().unwrap_or(0),
            clusters.iter().map(|c| c.ids.len()).max().unwrap_or(0),
            n / NUM_CLUSTERS,
        );

        *self.snapshot.write() = Some(Box::new(IndexSnapshot { clusters }));
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let snap = self.snapshot.read();
        let snapshot = snap.as_ref().unwrap();
        let clusters = &snapshot.clusters;

        // Find NPROBE nearest clusters using partial sort
        let mut cluster_dists: Vec<(usize, f32)> = Vec::with_capacity(NUM_CLUSTERS);
        for (i, c) in clusters.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(query, &c.centroid) };
            cluster_dists.push((i, dist));
        }

        cluster_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        let probe_clusters = &cluster_dists[..NPROBE];

        // Use binary heap for efficient top-k
        let mut heap = BinaryHeap::with_capacity(top_k + 1);
        let mut max_dist = f32::MAX;

        for &(cluster_idx, _) in probe_clusters {
            let cluster = &clusters[cluster_idx];
            let n = cluster.ids.len();
            if n == 0 {
                continue;
            }

            // Batch compute distances
            let mut dists = vec![0.0f32; n];
            unsafe {
                distance::l2_distances_batch(query, &cluster.vectors, n, &mut dists);
            }

            for i in 0..n {
                let dist = dists[i];
                if heap.len() < top_k {
                    heap.push(DistId { dist, id: cluster.ids[i] });
                    if heap.len() == top_k {
                        max_dist = heap.peek().unwrap().dist;
                    }
                } else if dist < max_dist {
                    // Replace max
                    *heap.peek_mut().unwrap() = DistId { dist, id: cluster.ids[i] };
                    max_dist = heap.peek().unwrap().dist;
                }
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_sorted_vec()
            .into_iter()
            .map(|d| SearchResult {
                id: d.id,
                distance: d.dist as f64,
            })
            .collect();

        results
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return Vec::new();
        }

        let chunk_size = (n + 3) / 4;
        let results: Vec<Vec<DistId>> = (0..4)
            .into_par_iter()
            .map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                let mut heap = BinaryHeap::with_capacity(top_k + 1);
                let mut max_dist = f32::MAX;

                for i in start..end {
                    let vec_slice = &vectors[i * DIM..(i + 1) * DIM];
                    let dist = unsafe { distance::l2_distance_fast(query, vec_slice) };

                    if heap.len() < top_k {
                        heap.push(DistId { dist, id: ids[i] });
                        if heap.len() == top_k {
                            max_dist = heap.peek().unwrap().dist;
                        }
                    } else if dist < max_dist {
                        *heap.peek_mut().unwrap() = DistId { dist, id: ids[i] };
                        max_dist = heap.peek().unwrap().dist;
                    }
                }

                heap.into_vec()
            })
            .collect();

        let mut merged = BinaryHeap::with_capacity(top_k + 1);
        for chunk in results {
            for d in chunk {
                if merged.len() < top_k {
                    merged.push(d);
                } else if d.dist < merged.peek().unwrap().dist {
                    *merged.peek_mut().unwrap() = d;
                }
            }
        }

        merged
            .into_sorted_vec()
            .into_iter()
            .map(|d| SearchResult {
                id: d.id,
                distance: d.dist as f64,
            })
            .collect()
    }
}

#[inline]
fn find_nearest_centroid_static(vec: &[f32], centroids: &[&[f32]]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::MAX;
    for (i, centroid) in centroids.iter().enumerate() {
        let dist = unsafe { distance::l2_distance_fast(vec, centroid) };
        if dist < best_dist {
            best_dist = dist;
            best_idx = i;
        }
    }
    best_idx
}

#[inline]
fn find_nearest_cluster_in_snapshot(vec: &[f32], clusters: &[Cluster]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::MAX;
    for (i, cluster) in clusters.iter().enumerate() {
        let dist = unsafe { distance::l2_distance_fast(vec, &cluster.centroid) };
        if dist < best_dist {
            best_dist = dist;
            best_idx = i;
        }
    }
    best_idx
}

fn kmeans(vectors: &[f32], n: usize) -> Vec<f32> {
    let sample_size = KMEANS_SAMPLE_SIZE.min(n);
    let step = if n > sample_size { n / sample_size } else { 1 };

    let sample_indices: Vec<usize> = (0..sample_size).map(|i| (i * step).min(n - 1)).collect();

    let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
    let init_step = if sample_size > NUM_CLUSTERS { sample_size / NUM_CLUSTERS } else { 1 };
    for c in 0..NUM_CLUSTERS {
        let idx = sample_indices[(c * init_step).min(sample_size - 1)];
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&vectors[idx * DIM..(idx + 1) * DIM]);
    }

    for _iter in 0..KMEANS_ITERS {
        let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

        let assignments: Vec<usize> = sample_indices
            .par_iter()
            .map(|&idx| {
                let vec = &vectors[idx * DIM..(idx + 1) * DIM];
                find_nearest_centroid_static(vec, &centroid_slices)
            })
            .collect();

        let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
        let mut counts = vec![0usize; NUM_CLUSTERS];

        for (si, &cluster_idx) in assignments.iter().enumerate() {
            let idx = sample_indices[si];
            counts[cluster_idx] += 1;
            let base = cluster_idx * DIM;
            let vbase = idx * DIM;
            for d in 0..DIM {
                new_centroids[base + d] += vectors[vbase + d] as f64;
            }
        }

        for c in 0..NUM_CLUSTERS {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
