        if self.index_built.load(Ordering::Relaxed) {
            // Copy centroids to avoid holding lock
            let centroid_data: Vec<[f32; DIM]> = {
                let snap_r = self.snapshot.read();
                match snap_r.as_ref() {
                    Some(s) => s.clusters.iter().map(|c| c.centroid).collect(),
                    None => return count,
                }
            };

            let centroid_refs: Vec<&[f32]> = centroid_data.iter().map(|c| c.as_slice()).collect();

            let assignments: Vec<(usize, u64, Vec<f32>)> = vectors
                .into_iter()
                .map(|(id, vec)| {
