    }

    fn build_index(&self) {
        if self.index_built.swap(true, Ordering::SeqCst) {
            return;
        }

        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            self.index_built.store(false, Ordering::SeqCst);
            return;
        }

        eprintln!("Building IVF index with {} vectors, {} clusters...", n, NUM_CLUSTERS);

        let centroids = kmeans(&vectors, n);

        let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

        let assignments: Vec<usize> = (0..n)
            .into_par_iter()
            .map(|i| {
                let vec = &vectors[i * DIM..(i + 1) * DIM];
                find_nearest_centroid_static(vec, &centroid_slices)
            })
            .collect();

        let mut cluster_ids: Vec<Vec<u64>> = (0..NUM_CLUSTERS).map(|_| Vec::new()).collect();
        let mut cluster_vecs: Vec<Vec<f32>> = (0..NUM_CLUSTERS).map(|_| Vec::new()).collect();

        for i in 0..n {
            let ci = assignments[i];
            cluster_ids[ci].push(ids[i]);
            cluster_vecs[ci].extend_from_slice(&vectors[i * DIM..(i + 1) * DIM]);
        }

        let clusters: Vec<Cluster> = (0..NUM_CLUSTERS)
            .map(|c| {
                let mut centroid = [0.0f32; DIM];
                centroid.copy_from_slice(&centroids[c * DIM..(c + 1) * DIM]);
                Cluster {
                    centroid,
                    ids: std::mem::take(&mut cluster_ids[c]),
                    vectors: std::mem::take(&mut cluster_vecs[c]),
                }
            })
            .collect();

        eprintln!("IVF index built. Cluster sizes: min={}, max={}, avg={}",
            clusters.iter().map(|c| c.ids.len()).min().unwrap_or(0),
            clusters.iter().map(|c| c.ids.len()).max().unwrap_or(0),
            n / NUM_CLUSTERS,
        );

        *self.snapshot.write() = Some(Box::new(IndexSnapshot { clusters }));
    }

    fn search_ivf(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let snap = self.snapshot.read();
        let snapshot = snap.as_ref().unwrap();
        let clusters = &snapshot.clusters;

        // Find NPROBE nearest clusters
        let mut cluster_dists: Vec<(usize, f32)> = Vec::with_capacity(NUM_CLUSTERS);
        for (i, c) in clusters.iter().enumerate() {
            let dist = unsafe { distance::l2_distance_fast(query, &c.centroid) };
            cluster_dists.push((i, dist));
        }

        cluster_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        let probe_indices: Vec<usize> = cluster_dists[..NPROBE].iter().map(|&(i, _)| i).collect();

        // Use binary heap for efficient top-k
        let mut heap = BinaryHeap::with_capacity(top_k + 1);
        let mut max_dist = f32::MAX;

        for &cluster_idx in &probe_indices {
            let cluster = &clusters[cluster_idx];
            let n = cluster.ids.len();
            if n == 0 {
                continue;
            }

            // Process in chunks for cache efficiency
            let mut dists = vec![0.0f32; n];
            unsafe {
                distance::l2_distances_batch(query, &cluster.vectors, n, &mut dists);
            }

            for i in 0..n {
                let dist = unsafe { *dists.get_unchecked(i) };
                if heap.len() < top_k {
                    heap.push(DistId { dist, id: unsafe { *cluster.ids.get_unchecked(i) } });
                    if heap.len() == top_k {
                        max_dist = heap.peek().unwrap().dist;
                    }
                } else if dist < max_dist {
                    *heap.peek_mut().unwrap() = DistId { dist, id: unsafe { *cluster.ids.get_unchecked(i) } };
                    max_dist = heap.peek().unwrap().dist;
                }
            }
        }

        heap.into_sorted_vec()
            .into_iter()
            .map(|d| SearchResult {
                id: d.id,
                distance: d.dist as f64,
            })
            .collect()
    }

    fn search_brute_force(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let ids = self.all_ids.read();
        let vectors = self.all_vectors.read();
        let n = ids.len();

        if n == 0 {
            return Vec::new();
        }

        let chunk_size = (n + 3) / 4;
        let results: Vec<Vec<DistId>> = (0..4)
            .into_par_iter()
            .map(|t| {
                let start = t * chunk_size;
                let end = (start + chunk_size).min(n);
                let mut heap = BinaryHeap::with_capacity(top_k + 1);
                let mut max_dist = f32::MAX;

                for i in start..end {
                    let vec_slice = &vectors[i * DIM..(i + 1) * DIM];
                    let dist = unsafe { distance::l2_distance_fast(query, vec_slice) };

                    if heap.len() < top_k {
                        heap.push(DistId { dist, id: ids[i] });
                        if heap.len() == top_k {
                            max_dist = heap.peek().unwrap().dist;
                        }
                    } else if dist < max_dist {
                        *heap.peek_mut().unwrap() = DistId { dist, id: ids[i] };
                        max_dist = heap.peek().unwrap().dist;
                    }
                }

                heap.into_vec()
            })
            .collect();

        let mut merged = BinaryHeap::with_capacity(top_k + 1);
        for chunk in results {
            for d in chunk {
                if merged.len() < top_k {
                    merged.push(d);
                } else if d.dist < merged.peek().unwrap().dist {
                    *merged.peek_mut().unwrap() = d;
                }
            }
        }

        merged
            .into_sorted_vec()
            .into_iter()
            .map(|d| SearchResult {
                id: d.id,
                distance: d.dist as f64,
            })
            .collect()
    }
}

#[inline]
fn find_nearest_centroid_static(vec: &[f32], centroids: &[&[f32]]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::MAX;
    for (i, centroid) in centroids.iter().enumerate() {
        let dist = unsafe { distance::l2_distance_fast(vec, centroid) };
        if dist < best_dist {
            best_dist = dist;
            best_idx = i;
        }
    }
    best_idx
}

#[inline]
fn find_nearest_cluster_in_snapshot(vec: &[f32], clusters: &[Cluster]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::MAX;
    for (i, cluster) in clusters.iter().enumerate() {
        let dist = unsafe { distance::l2_distance_fast(vec, &cluster.centroid) };
        if dist < best_dist {
            best_dist = dist;
            best_idx = i;
        }
    }
    best_idx
}

fn kmeans(vectors: &[f32], n: usize) -> Vec<f32> {
    let sample_size = KMEANS_SAMPLE_SIZE.min(n);
    let step = if n > sample_size { n / sample_size } else { 1 };

    let sample_indices: Vec<usize> = (0..sample_size).map(|i| (i * step).min(n - 1)).collect();

    let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
    let init_step = if sample_size > NUM_CLUSTERS { sample_size / NUM_CLUSTERS } else { 1 };
    for c in 0..NUM_CLUSTERS {
        let idx = sample_indices[(c * init_step).min(sample_size - 1)];
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&vectors[idx * DIM..(idx + 1) * DIM]);
    }

    for _iter in 0..KMEANS_ITERS {
        let centroid_slices: Vec<&[f32]> = centroids.chunks(DIM).collect();

        let assignments: Vec<usize> = sample_indices
            .par_iter()
            .map(|&idx| {
                let vec = &vectors[idx * DIM..(idx + 1) * DIM];
                find_nearest_centroid_static(vec, &centroid_slices)
            })
            .collect();

        let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
        let mut counts = vec![0usize; NUM_CLUSTERS];

        for (si, &cluster_idx) in assignments.iter().enumerate() {
            let idx = sample_indices[si];
            counts[cluster_idx] += 1;
            let base = cluster_idx * DIM;
            let vbase = idx * DIM;
            for d in 0..DIM {
                new_centroids[base + d] += vectors[vbase + d] as f64;
            }
        }

        for c in 0..NUM_CLUSTERS {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
