        let count = vectors.len();

        if self.index_built.load(Ordering::Relaxed) {
            let centroid_copy: Vec<f32> = {
                let idx = self.index.read();
                match idx.as_ref() {
                    Some(ivf) => ivf.centroids.clone(),
                    None => return count,
                }
            };

