        } else {
            {
                let mut ids = self.all_ids.write();
                let mut vecs = self.all_vectors.write();
                for (id, vector) in &vectors {
                    ids.push(*id);
                    vecs.extend_from_slice(vector);
                }
            }

            let total = self.vector_count.fetch_add(count, Ordering::Relaxed) + count;
